
.status-card {
  position: relative;
  width: 100%;
  max-width: 380px;
  margin: 0 auto;
  font-family: var(--font-mono);
  color: var(--c-text);
  font-size: 11px;
  line-height: 1.45;
  border: 1px solid var(--c-border);
  border-radius: 10px;
  overflow: hidden;
}

.wave-bg {
  position: absolute;
  inset: 0;
  z-index: 0;
  background:
    radial-gradient(ellipse at 20% 80%, rgba(180, 40, 40, 0.25) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 20%, rgba(200, 60, 60, 0.15) 0%, transparent 50%),
    radial-gradient(ellipse at 50% 50%, rgba(140, 20, 20, 0.3) 0%, transparent 70%),
    linear-gradient(180deg, var(--c-bg-deep) 0%, var(--c-bg-mid) 50%, var(--c-bg-deep) 100%);
  background-size: 200% 200%;
  animation: waveFlow 8s ease-in-out infinite;
}

@keyframes waveFlow {
  0%, 100% { background-position: 0% 0%; }
  25% { background-position: 100% 30%; }
  50% { background-position: 50% 100%; }
  75% { background-position: 0% 70%; }
}

.card-content {
  position: relative;
  z-index: 1;
}

.info-section {
  padding: 14px 16px 4px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.info-row {
  font-size: 0.8rem;
  font-weight: bold;
  color: var(--c-text);
}

.stats-section {
  padding: 10px 16px 14px;
  display: flex;
  flex-direction: column;
  gap: 7px;
}

.stat-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.stat-icon {
  font-size: 0.85rem;
  width: 18px;
  text-align: center;
}

.stat-name {
  font-weight: bold;
  font-size: 0.7rem;
  min-width: 40px;
  color: var(--c-text-dim);
}

.stat-val {
  font-weight: bold;
  font-size: 0.7rem;
  color: var(--c-text);
}

.stat-bar-wrap {
  flex: 1;
  position: relative;
  height: 17px;
  display: flex;
  align-items: center;
}

.stat-bar {
  width: 100%;
  height: 5px;
  border-radius: 3px;
  background: rgba(255, 255, 255, 0.06);
  overflow: hidden;
}

.bar-val {
  position: absolute;
  right: 0;
  top: -2px;
  font-size: 0.55rem;
  font-weight: bold;
  color: var(--c-text-dim);
}

.money-val {
  font-size: 0.6rem;
  font-weight: bold;
  color: var(--c-text);
}

.fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.35s ease;
}

.fill.food     { background: #e8a850; }
.fill.spirit   { background: #5badd4; }
.fill.mood     { background: #c47ab4; }
.fill.erotica  { background: #c44a6a; }
.fill.libido   { background: #e05555; }
.fill.pleasure { background: linear-gradient(90deg, #e8a850, #e05555); }

@media (max-width: 400px) {
  .status-card { max-width: 100%; }
  .stat-row { flex-wrap: wrap; }
}
